lxslt:component.lxslt:script:
function convertToYYYYMMDDHH24MISS_minus1(input) {

    if (!input || typeof input !== "string") {
        throw new Error("Invalid input: expected non-empty string in format YYYY-MM-DDTHH:MI:SS±HH:MM00000");
    }

    // Trim and remove trailing "00000" if present
    var raw = input.trim();
    var clean = raw.replace(/00000$/, "");

    // Extract timezone like "+05:30" or "-04:00"
    var tzMatch = clean.match(/([+\-]\d{2}:\d{2})$/);

    if (!tzMatch) {
        tzMatch = clean.match(/([+\-]\d{2}:\d{2})/);
    }

    if (!tzMatch) {
        throw new Error("Timezone not found in input: " + input);
    }
    var tz = tzMatch[1];

    // Parse ISO string (let JS engine interpret timezone)
    var parsedMs = Date.parse(clean);
    if (isNaN(parsedMs)) {
        throw new Error("Failed to parse date after cleaning: " + clean);
    }

    // Subtract exactly one day (24 * 60 * 60 * 1000)
    var ONE_DAY_MS = 24 * 60 * 60 * 1000;
    var newUtcMs = parsedMs - ONE_DAY_MS;

    // Compute timezone offset minutes from tz string
    var sign = (tz.charAt(0) === "-") ? -1 : 1;
    var tzParts = tz.substring(1).split(":");
    var tzH = parseInt(tzParts[0], 10);
    var tzM = parseInt(tzParts[1], 10);

    if (isNaN(tzH) || isNaN(tzM)) {
        throw new Error("Invalid timezone format: " + tz);
    }
    var offsetMinutes = sign * (tzH * 60 + tzM);

    // Convert the new UTC instant back to "local fields" in the original timezone:
    // localMs = newUtcMs + offsetMinutes*60000
    var localMs = newUtcMs + (offsetMinutes * 60000);
    var outDate = new Date(localMs);

    // Helper pad
    function pad(n) { n = String(n); return (n.length < 2 ? "0" + n : n); }

    // Use UTC getters because we adjusted ms to represent the local fields

    var outY = outDate.getUTCFullYear();
    var outMo = outDate.getUTCMonth() + 1;
    var outD = outDate.getUTCDate();
    var outH = outDate.getUTCHours();
    var outMin = outDate.getUTCMinutes();
    var outS = outDate.getUTCSeconds();

    return String(outY) + pad(outMo) + pad(outD) + pad(outH) + pad(outMin) + pad(outS);
}

function convertToYYYYMMDDHH24MISS(input) {

  // Extract timezone part without the 00000
  var timezoneMatch = input.match(/([+\-]\d{2}:\d{2})/);
  if (!timezoneMatch) {
    throw "Invalid input: timezone not found in +/-HH:MM00000 format.";
  }

  var tz = timezoneMatch[1];  // e.g. "+05:30"

  // Remove trailing "00000"
  var cleanInput = input.replace(/00000$/, "");

  // ISO string is already correct once trimmed
  var isoString = cleanInput;

  // Create Date object
  var date = new Date(isoString);

  // Helper to pad numbers
  function pad(num) {
    num = String(num);
    return (num.length < 2 ? "0" + num : num);
  }

  var YYYY = date.getFullYear();
  var MM = pad(date.getMonth() + 1);
  var DD = pad(date.getDate());
  var HH = pad(date.getHours());
  var MI = pad(date.getMinutes());
  var SS = pad(date.getSeconds());

  return "" + YYYY + MM + DD + HH + MI + SS;
}
